#include <stdio.h>
#include <stdint.h>

static uint64_t isqrt_ceil(uint64_t n) {
    uint64_t lo = 0, hi = 1000000000ULL + 1; // sqrt(1e18) = 1e9
    while (lo + 1 < hi) {
        uint64_t mid = lo + (hi - lo) / 2;
        if (mid * mid >= n) hi = mid; else lo = mid;
    }
    return hi;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        printf("%llu\n", isqrt_ceil(N));
    }
    return 0;
}

