import sys

def ceil_sqrt(n: int) -> int:
    lo, hi = 0, 10**9 + 1  # sqrt(1e18) = 1e9
    while lo + 1 < hi:
        mid = (lo + hi) // 2
        if mid * mid >= n:
            hi = mid
        else:
            lo = mid
    return hi

data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
out = []
idx = 1
for _ in range(T):
    N = int(data[idx]); idx += 1
    out.append(str(ceil_sqrt(N)))
print('\n'.join(out))

